            border: none; border-radius: 0.5rem; font-weight: 600;
            cursor: pointer; margin-top: 0.8rem;
            font-family: var(--font-family);
        }

        .btn-secondary {
            width: 100%; padding: 0.6rem; background: transparent;
            color: var(--color-text-main); opacity: 0.8;
            border: 1px solid var(--color-border-soft); border-radius: 0.5rem;
            cursor: pointer; margin-top: 0.5rem; font-size: 0.9rem;
            font-family: var(--font-family);
        }
        .btn-secondary:hover { opacity: 1; border-color: var(--color-primary); color: var(--color-primary); }

        #raw-options-data { display: none; }
        .toast {
            position: fixed; bottom: 2rem; left: 50%; transform: translateX(-50%) translateY(100px);
            background-color: var(--color-primary); color: white; padding: 0.5rem 1.2rem;
            border-radius: 2rem; font-size: 0.85rem; opacity: 0; transition: all 0.3s ease;
            pointer-events: none; z-index: 10000;
            font-family: var(--font-family);
        }
        .toast.show { transform: translateX(-50%) translateY(0); opacity: 1; }
    </style>
</head>
<body>
    <div class="header">
        <h1 class="page-title"><user>的抉择</h1>
        <button class="settings-btn" title="设置">⚙️</button>
    </div>

    <textarea id="raw-options-data">$1</textarea>

    <div id="options-container"></div>

    <div id="toast" class="toast">设置已保存</div>

    <div class="settings-panel">
        <div class="settings-content">
            <div class="settings-header">
                <h2 class="settings-title">设置</h2>
                <button class="close-btn">&times;</button>
            </div>

            <div class="settings-group">
                <label class="settings-label">点击选项时：</label>
                <label class="radio-label">
                    <input type="radio" name="action-mode" value="send-to-chat" checked>
                    <span>添加到输入框 (不发送)</span>
                </label>
                <label class="radio-label">
                    <input type="radio" name="action-mode" value="direct-execute">
                    <span>直接发送并执行</span>
                </label>
            </div>

            <div class="settings-group">
                <label class="settings-label">字体样式</label>
                <select id="font-family-select" class="select-field">
                    <option value="system-ui, -apple-system, sans-serif">系统默认</option>
                    <option value="'Noto Sans SC', system-ui, sans-serif">思源黑体</option>
                    <option value="'ZCOOL XiaoWei', serif">站酷小薇</option>
                    <option value="'Ma Shan Zheng', cursive">马善政楷书</option>
                    <option value="'Long Cang', cursive">龙藏体</option>
                    <option value="'Pixelify Sans', sans-serif">Pixelify Sans</option>
                    <option value="'Roboto', sans-serif">Roboto</option>
                    <option value="serif">衬线体</option>
                    <option value="monospace">等宽字体</option>
                </select>
            </div>

            <div class="settings-group">
                <label class="settings-label">背景颜色</label>
                <div class="color-input-wrapper">
                    <input type="color" id="bg-color-picker" class="color-input" value="#FFFFFF">
                    <input type="text" id="bg-color-text" class="input-field" value="#FFFFFF">
                </div>
            </div>

            <div class="settings-group">
                <label class="settings-label">文字颜色</label>
                <div class="color-input-wrapper">
                    <input type="color" id="text-color-picker" class="color-input" value="#2C3E50">
                    <input type="text" id="text-color-text" class="input-field" value="#2C3E50">
                </div>
            </div>

            <div class="settings-group">
                <label class="settings-label">高亮色</label>
                <div class="color-input-wrapper">
                    <input type="color" id="primary-color-picker" class="color-input" value="#5DADE2">
                    <input type="text" id="primary-color-text" class="input-field" value="#5DADE2">
                </div>
            </div>

            <button class="btn-primary" onclick="saveSettings()">保存</button>
            <button class="btn-secondary" onclick="resetSettings()">重置</button>
        </div>
    </div>

    <script>
        const DEFAULT_SETTINGS = {
            actionMode: 'send-to-chat',
            backgroundColor: '#FFFFFF',
            textColor: '#2C3E50',
            primaryColor: '#5DADE2',
            fontFamily: 'system-ui, -apple-system, sans-serif'
        };

        function parseAndGenerateOptions() {
            const rawData = document.getElementById('raw-options-data').value;
            const container = document.getElementById('options-container');
            if (!rawData) return;
            const lines = rawData.split(/\r?\n/).filter(line => line.trim() !== '');
            lines.forEach(line => {
                let cleanText = line.trim().replace(/^(\d+\.|-|•)\s*/, '');
                if (cleanText) {
                    const btn = document.createElement('button');
                    btn.className = 'option-button';
                    btn.textContent = cleanText;
                    btn.addEventListener('click', () => handleOptionClick(cleanText, btn));
                    container.appendChild(btn);
                }
            });
            if (container.children.length === 0) {
                container.innerHTML = '<div style="color:var(--color-text-main);opacity:0.6;text-align:center;font-size:0.9rem">未检测到选项</div>';
            }
        }

        function handleOptionClick(text, btnElement) {
            const settings = getSettings();
            btnElement.style.transform = 'scale(0.99)';
            setTimeout(() => btnElement.style.transform = '', 100);
            if (settings.actionMode === 'send-to-chat') {
                sendToChatBox(text);
            } else {
                triggerQuickReply(text);
            }
        }

        function sendToChatBox(text) {
            try {
                const textarea = parent.document.querySelector('#send_textarea');
                if (textarea) {
                    const currentVal = textarea.value;
                    if (currentVal.trim() !== '') {
                        if (!currentVal.includes(text)) {
                            textarea.value = currentVal + '\n' + text;
                        }
                    } else {
                        textarea.value = text;
                    }
                    textarea.dispatchEvent(new Event('input', { bubbles: true }));
                    textarea.focus();
                } else {
                    triggerQuickReply(text);
                }
            } catch (e) {
                console.error(e);
            }
        }

        const triggerQuickReply = text => {
            if (typeof triggerSlash === 'function') {
                triggerSlash(`/send ${text}|/trigger`);
            } else {
                console.log('Mock Send:', text);
            }
        };

        function getSettings() {
            try {
                return JSON.parse(localStorage.getItem('userChoiceSettings')) || DEFAULT_SETTINGS;
            } catch {
                return DEFAULT_SETTINGS;
            }
        }

        function applySettings(settings) {
            const root = document.documentElement;

            // 应用核心颜色变量
            root.style.setProperty('--color-background-main', settings.backgroundColor);
            root.style.setProperty('--color-text-main', settings.textColor);
            root.style.setProperty('--color-primary', settings.primaryColor);
            root.style.setProperty('--font-family', settings.fontFamily);

            // 计算辅助色：边框颜色为主色的 30% 透明度
            root.style.setProperty('--color-border-soft', adjustColor(settings.primaryColor, 40) + '4D');

            if(document.getElementById('bg-color-picker')) {
                document.getElementById('bg-color-picker').value = settings.backgroundColor;
                document.getElementById('bg-color-text').value = settings.backgroundColor;
                document.getElementById('text-color-picker').value = settings.textColor;
                document.getElementById('text-color-text').value = settings.textColor;
                document.getElementById('primary-color-picker').value = settings.primaryColor;
                document.getElementById('primary-color-text').value = settings.primaryColor;
                document.getElementById('font-family-select').value = settings.fontFamily;
                const radio = document.querySelector(`input[name="action-mode"][value="${settings.actionMode}"]`);
                if (radio) radio.checked = true;
            }
        }

        function saveSettings() {
            const settings = {
                actionMode: document.querySelector('input[name="action-mode"]:checked').value,
                backgroundColor: document.getElementById('bg-color-text').value,
                textColor: document.getElementById('text-color-text').value,
                primaryColor: document.getElementById('primary-color-text').value,
                fontFamily: document.getElementById('font-family-select').value
            };
            localStorage.setItem('userChoiceSettings', JSON.stringify(settings));
            applySettings(settings);
            const toast = document.getElementById('toast');
            toast.classList.add('show');
            setTimeout(() => toast.classList.remove('show'), 2000);
            document.querySelector('.settings-panel').style.display = 'none';
        }

        function resetSettings() {
            if(confirm('恢复默认设置？')) {
                localStorage.removeItem('userChoiceSettings');
                applySettings(DEFAULT_SETTINGS);
                document.querySelector('.settings-panel').style.display = 'none';
            }
        }

        function adjustColor(hex, amt) {
            let usePound = false;
            if (hex[0] === "#") { hex = hex.slice(1); usePound = true; }
            let num = parseInt(hex, 16);
            let r = (num >> 16) + amt; if (r > 255) r = 255; else if (r < 0) r = 0;
            let g = ((num >> 8) & 0x00FF) + amt; if (g > 255) g = 255; else if (g < 0) g = 0;
            let b = (num & 0x0000FF) + amt; if (b > 255) b = 255; else if (b < 0) b = 0;
            return (usePound ? "#" : "") + (g | (b << 8) | (r << 16)).toString(16).padStart(6,'0');
        }

        document.addEventListener('DOMContentLoaded', () => {
            applySettings(getSettings());
            parseAndGenerateOptions();
            const panel = document.querySelector('.settings-panel');
            document.querySelector('.settings-btn').onclick = () => panel.style.display = 'flex';
            document.querySelector('.close-btn').onclick = () => panel.style.display = 'none';
            ['bg', 'text', 'primary'].forEach(type => {
                const picker = document.getElementById(`${type}-color-picker`);
                const text = document.getElementById(`${type}-color-text`);
                if(picker && text) {
                    picker.addEventListener('input', e => text.value = e.target.value.toUpperCase());
                    text.addEventListener('input', e => picker.value = e.target.value);
                }
            });
        });
    </script>
</body>
</html>
