/**
 * HistorySquash —— SillyTavern 发送前 prompt 轻量重排脚本
 * =========================================================
 *
 * 这个脚本解决什么问题？
 * --------------------
 * 在 SillyTavern 构建好即将发送给模型的 Chat Completion prompt 后，
 * 查找 `<|history|>` 与 `<|/history|>` 两个 marker 之间的消息，
 * 将其中的 user / assistant / system / tool 消息压扁成一条连续文本，
 * 再以一个指定 role（默认 system）插回 prompt 数组。
 *
 * 默认输出格式类似：
 *
 *   user:
 *   第一条用户消息
 *
 *   assistant:
 *   第一条助手回复
 *
 *   user:
 *   第二条用户消息
 *
 * 这个脚本不会做什么？
 * ------------------
 * - 不修改 preset 文件。
 * - 不修改 SillyTavern 的 prompts / prompt_order。
 * - 不注入远程 HTML。
 * - 不使用 eval / new Function。
 * - 不轮询。禁止 setInterval / setTimeout 形式的挂载重试。
 *
 * 使用的 SillyTavern 原生/推荐机制
 * -----------------------------
 * - 通过 SillyTavern.getContext() 获取上下文。
 * - 通过 ctx.eventSource 监听 ctx.eventTypes.GENERATE_AFTER_DATA。
 *   这是发送前、prompt 数组已经构建完成后较合适的改写点。
 * - UI 挂到主界面的 #extensions_settings / #extensions_settings2。
 * - UI 使用 SillyTavern 原生样式类：
 *   extension_container、inline-drawer、inline-drawer-toggle、
 *   inline-drawer-content、menu_button、text_pole 等。
 * - 抽屉展开/折叠交给 SillyTavern 原生的全局 click 代理处理；
 *   本脚本不手写 drawer toggle，避免与 ST 自身逻辑冲突。
 * - UI 出现时机只靠事件与 MutationObserver 监听，不做定时轮询。
 *
 * 为什么要同时检查 window / parent / top？
 * --------------------------------------
 * 有些第三方脚本加载器会把脚本放在 iframe 或类似沙盒环境里运行。
 * 这种情况下，当前 window 可能不是 SillyTavern 主界面。
 * 因此脚本会在可访问的 window、parent、top 中寻找：
 * - SillyTavern.getContext()
 * - #extensions_settings / #extensions_settings2
 *
 * 公开调试 API
 * -----------
 * window.HistorySquash.getSettings()
 * window.HistorySquash.setSettings({...})
 * window.HistorySquash.runPreview(jsonText)
 * window.HistorySquash.getLast()
 * window.HistorySquash.mount()
 * window.HistorySquash.diagnose()
 */

(() => {
  'use strict';

  // ===========================================================================
  // 1. 常量、默认设置与运行时状态
  // ===========================================================================

  /**
   * 设置保存键。
   *
   * 这里选择 localStorage，而不是写入 preset/prompt。
   * 原因：这个脚本定位是“轻量外部脚本”，设置属于浏览器侧调试偏好，
   * 不应污染用户的 SillyTavern preset 数据结构。
   */
  const STORAGE_KEY = 'HistorySquash.settings.v1';

  /** @type {HistorySquashSettings} */
  const DEFAULT_SETTINGS = {
    enabled: true,
    debug: false,
    templateDialogueOnly: true,
    startMarker: '<|history|>',
    endMarker: '<|/history|>',
    outputRole: 'assistant',
    blockTemplate: '{{role}}:\n{{content}}',
    joiner: '\n\n',
    labels: {
      user: 'User',
      assistant: 'Assistant',
      system: 'System',
      tool: 'Tool',
    },
  };

  /**
   * 运行时状态。
   *
   * installed：避免重复绑定 GENERATE_AFTER_DATA。
   * uiObservers：保存 MutationObserver，避免重复安装。
   * lastBefore / lastAfter：用于 UI 调试，不参与真实请求逻辑。
   */
  const state = {
    settings: loadSettings(),
    lastBefore: null,
    lastAfter: null,
    lastChanged: false,
    installed: false,
    uiObservers: [],
    uiMountAttempts: 0,
    uiMountedAt: null,
  };

  // ===========================================================================
  // 2. 类型说明（JSDoc，仅用于阅读和编辑器提示）
  // ===========================================================================

  /**
   * @typedef {object} HistorySquashSettings
   * @property {boolean} enabled 是否启用发送前改写。
   * @property {boolean} debug 是否输出控制台调试信息。
   * @property {boolean} templateDialogueOnly 是否只给 user/assistant 套模板；其它结构片段作为同一条输出消息内的普通文本。
   * @property {string} startMarker 历史压缩开始标记。
   * @property {string} endMarker 历史压缩结束标记。
   * @property {'system'|'user'|'assistant'|string} outputRole 压扁后新消息的 role。
   * @property {string} blockTemplate 单条消息模板，可用 {{role}} / {{rawRole}} / {{content}}。
   * @property {string} joiner 多条消息块之间的连接符。
   * @property {Record<string, string>} labels role 到展示标签的映射。
   */

  // ===========================================================================
  // 3. 基础工具：设置、窗口探测、上下文探测
  // ===========================================================================

  function structuredCloneCompat(value) {
    // 只处理本脚本使用的 JSON 兼容数据，避免旧环境没有 structuredClone。
    return JSON.parse(JSON.stringify(value));
  }

  function mergeSettings(base, override) {
    return {
      ...structuredCloneCompat(base),
      ...(override || {}),
      labels: {
        ...base.labels,
        ...((override && override.labels) || {}),
      },
    };
  }

  function loadSettings() {
    try {
      const saved = JSON.parse(localStorage.getItem(STORAGE_KEY) || 'null');
      return mergeSettings(DEFAULT_SETTINGS, saved || {});
    } catch (error) {
      console.warn('[HistorySquash] 设置读取失败，使用默认设置。', error);
      return structuredCloneCompat(DEFAULT_SETTINGS);
    }
  }

  function saveSettings() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state.settings));
  }

  /**
   * 返回当前脚本可以访问的候选 window。
   *
   * best effort：跨域 iframe 可能访问失败，所以所有访问都包 try/catch。
   */
  function getCandidateWindows() {
    const result = [];
    for (const win of [window, window.parent, window.top]) {
      try {
        if (win && !result.includes(win)) result.push(win);
      } catch {
        // 跨域或不可访问，忽略。
      }
    }
    return result;
  }

  /**
   * 在可访问 window 中寻找 SillyTavern context。
   *
   * 优先使用官方暴露的 SillyTavern.getContext()。
   */
  function getSillyTavernContext() {
    for (const win of getCandidateWindows()) {
      try {
        const ctx = win.SillyTavern?.getContext?.();
        if (ctx?.eventSource && ctx?.eventTypes) return ctx;
      } catch {
        // 不是 SillyTavern 主窗口或不可访问，忽略。
      }
    }
    return null;
  }

  /**
   * 找到应该挂载 UI 的 document。
   *
   * 如果脚本在 iframe 中执行，但 parent/top 是酒馆主页面，
   * 这里会返回主页面 document。
   */
  function getUIDocument() {
    for (const win of getCandidateWindows()) {
      try {
        const doc = win.document;
        if (doc?.querySelector?.('#extensions_settings, #extensions_settings2')) return doc;
      } catch {
        // 不可访问，忽略。
      }
    }
    return document;
  }

  /**
   * 把调试 API 暴露到所有可访问 window。
   *
   * 这样无论用户控制台当前选中的是主窗口还是 iframe，
   * 都更容易访问 HistorySquash。
   */
  function exposeApi(api) {
    for (const win of getCandidateWindows()) {
      try {
        win.HistorySquash = api;
      } catch {
        // 不可访问，忽略。
      }
    }
  }

  // ===========================================================================
  // 4. prompt 内容处理逻辑
  // ===========================================================================

  /**
   * 提取 OpenAI chat message content 中的纯文本。
   *
   * ST 的 prompt.content 常见形态：
   * - string
   * - 多模态数组：[{ type: 'text', text: '...' }, { type: 'image_url', ... }]
   *
   * 本脚本的压扁目标是文本历史；非文本附件不会主动展开。
   */
  function getTextContent(content) {
    if (typeof content === 'string') return content;
    if (Array.isArray(content)) {
      return content
        .filter(part => part && part.type === 'text' && typeof part.text === 'string')
        .map(part => part.text)
        .join('');
    }
    return '';
  }

  function cloneMessageWithContent(message, content) {
    return { ...message, content };
  }

  /**
   * 只有非空文本才推入目标数组。
   * 用于保留 marker 前后的边界文本。
   */
  function pushIfContent(target, message, content) {
    const text = typeof content === 'string' ? content : getTextContent(content);
    if (!text || !text.trim()) return;
    target.push(cloneMessageWithContent(message, text));
  }

  /**
   * 将单条消息转为模板块。
   */
  function messageToFlatBlock(message) {
    const rawRole = message.role || 'unknown';
    const content = getTextContent(message.content).trim();
    if (!content) return '';

    // history marker 内经常会放结构性片段，例如：
    //
    //   <!-- 前情概要 -->
    //   <history>
    //   ...
    //   </history>
    //
    // 这些片段是容器/标签，不是一轮 user/assistant 对话。
    // 默认原样拼入“同一条输出消息”的 content，避免输出成：
    //
    //   system:
    //   <history>
    //
    // 注意：这不会保留原 role。最终消息的 role 始终由 outputRole 决定。
    // 如果 outputRole=user，压扁结果就是一条连续的 user 消息。
    if (state.settings.templateDialogueOnly && rawRole !== 'user' && rawRole !== 'assistant') {
      return content;
    }

    const role = state.settings.labels[rawRole] || rawRole;
    return state.settings.blockTemplate
      .replaceAll('{{role}}', role)
      .replaceAll('{{rawRole}}', rawRole)
      .replaceAll('{{content}}', content);
  }

  /**
   * 将已收集的 historyMessages 压成一条新消息。
   */
  function flushHistory(output, historyMessages) {
    const content = historyMessages
      .map(messageToFlatBlock)
      .filter(Boolean)
      .join(state.settings.joiner);

    if (!content.trim()) return;

    output.push({
      role: state.settings.outputRole || DEFAULT_SETTINGS.outputRole,
      content,
    });
  }

  /**
   * 原地改写 prompt 数组。
   *
   * 支持两类边界：
   *
   * 1. marker 独立成消息：
   *    system: <|history|>
   *    user: ...
   *    assistant: ...
   *    system: <|/history|>
   *
   * 2. marker 与其他文本同处一条消息：
   *    system: before <|history|>
   *    ...history...
   *    system: <|/history|> after
   *
   * 如果只有开始 marker、没有结束 marker，则 fail open：不改 prompt。
   */
  function squashHistoryBetweenMarkers(prompts) {
    if (!Array.isArray(prompts)) return false;
    if (!state.settings.enabled) return false;

    const output = [];
    const history = [];
    let inside = false;
    let changed = false;

    for (const message of prompts) {
      const text = getTextContent(message.content);
      const startIndex = text.indexOf(state.settings.startMarker);
      const endIndex = text.indexOf(state.settings.endMarker);

      if (!inside) {
        if (startIndex === -1) {
          output.push(message);
          continue;
        }

        changed = true;
        const before = text.slice(0, startIndex);
        const afterStart = text.slice(startIndex + state.settings.startMarker.length);

        pushIfContent(output, message, before);

        // 开始和结束 marker 在同一条消息中。
        if (afterStart.includes(state.settings.endMarker)) {
          const innerEndIndex = afterStart.indexOf(state.settings.endMarker);
          const inner = afterStart.slice(0, innerEndIndex);
          const after = afterStart.slice(innerEndIndex + state.settings.endMarker.length);

          pushIfContent(history, message, inner);
          flushHistory(output, history);
          history.length = 0;
          pushIfContent(output, message, after);
          inside = false;
        } else {
          pushIfContent(history, message, afterStart);
          inside = true;
        }
        continue;
      }

      // 已在 <|history|> ... <|/history|> 区间内。
      if (endIndex === -1) {
        history.push(message);
        continue;
      }

      changed = true;
      const beforeEnd = text.slice(0, endIndex);
      const afterEnd = text.slice(endIndex + state.settings.endMarker.length);

      pushIfContent(history, message, beforeEnd);
      flushHistory(output, history);
      history.length = 0;
      pushIfContent(output, message, afterEnd);
      inside = false;
    }

    if (inside) {
      console.warn('[HistorySquash] 找到开始 marker 但没有找到结束 marker；本次 prompt 保持原样。');
      return false;
    }

    if (!changed) return false;

    prompts.length = 0;
    prompts.push(...output);
    return true;
  }

  function stringifyPrompt(prompt) {
    return JSON.stringify(prompt, null, 2);
  }

  /**
   * UI 里的离线预览，不影响真实请求。
   */
  function runPreview(inputText) {
    let prompt;
    try {
      prompt = JSON.parse(inputText);
      if (!Array.isArray(prompt)) throw new Error('JSON root must be an array.');
    } catch (error) {
      return { ok: false, text: `JSON 解析失败：${error.message}` };
    }

    const before = structuredCloneCompat(prompt);
    const changed = squashHistoryBetweenMarkers(prompt);
    return {
      ok: true,
      changed,
      text: stringifyPrompt(prompt),
      before,
      after: prompt,
    };
  }

  // ===========================================================================
  // 5. UI：挂载到“魔法棒 → 扩展程序”
  // ===========================================================================

  /**
   * 创建设置面板。
   *
   * 注意：这里只创建 DOM，不做轮询。
   * 如果挂载点尚不存在，返回 false，让调用方等待 DOM 事件或 MutationObserver。
   */
  function createPanel() {
    const uiDocument = getUIDocument();
    const existing = uiDocument.getElementById('history-squash-settings');
    if (existing && uiDocument.body?.contains(existing)) {
      state.uiMountedAt = state.uiMountedAt || new Date().toISOString();
      return true;
    }

    const mount = uiDocument.querySelector('#extensions_settings') || uiDocument.querySelector('#extensions_settings2');
    state.uiMountAttempts += 1;
    if (!mount) {
      if (state.settings.debug) {
        console.debug('[HistorySquash] 扩展设置挂载点尚未出现。', {
          attempts: state.uiMountAttempts,
          readyState: uiDocument.readyState,
          hasExtensionsBlock: !!uiDocument.querySelector('#rm_extensions_block'),
        });
      }
      return false;
    }

    if (!uiDocument.getElementById('history-squash-style')) {
      const style = uiDocument.createElement('style');
      style.id = 'history-squash-style';
      style.textContent = `
        #history-squash-settings .hs-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 8px; }
        #history-squash-settings .hs-checks { display: flex; gap: 14px; align-items: center; flex-wrap: wrap; margin: 6px 0; }
        #history-squash-settings .hs-checks label { display: flex; align-items: center; gap: 6px; margin: 0; }
        #history-squash-settings label.hs-field { display: grid; gap: 4px; margin: 8px 0; }
        #history-squash-settings textarea { min-height: 82px; font-family: var(--monoFontFamily, ui-monospace, monospace); font-size: 12px; }
        #history-squash-settings .hs-actions { display: flex; gap: 8px; flex-wrap: wrap; margin: 10px 0; }
        #history-squash-settings .hs-note { opacity: .75; font-size: 12px; white-space: pre-wrap; }
        #history-squash-settings .hs-output { min-height: 130px; }
        /*
         * ST 原生扩展区会给 .inline-drawer-header 设置 margin-bottom: 5px。
         * 对普通扩展没问题，但本脚本收起时只剩一个标题条，视觉上会显得“下方空白比上方多”。
         * 这里仅对 HistorySquash 局部覆盖：收起时更齐，展开时内容本身有字段间距，不需要 header 额外撑开。
         */
        #history-squash-settings .inline-drawer-toggle.inline-drawer-header { margin-bottom: 0; }
        @media (max-width: 700px) { #history-squash-settings .hs-grid { grid-template-columns: 1fr; } }
      `;
      uiDocument.head.appendChild(style);
    }

    const root = uiDocument.createElement('div');
    root.id = 'history-squash-settings';
    root.className = 'extension_container';
    root.innerHTML = `
      <div class="inline-drawer">
        <div class="inline-drawer-toggle inline-drawer-header">
          <b><i class="fa-solid fa-wand-magic-sparkles"></i> HistorySquash</b>
          <div class="inline-drawer-icon fa-solid fa-circle-chevron-down down"></div>
        </div>
        <div class="inline-drawer-content">
          <div class="hs-note">发送前把 <code>&lt;|history|&gt;</code> 与 <code>&lt;|/history|&gt;</code> 之间的消息压成一条消息；只改本次请求，不写 preset。</div>

          <div class="hs-checks">
            <label class="checkbox_label"><input id="hs-enabled" type="checkbox"><span>启用</span></label>
            <label class="checkbox_label"><input id="hs-debug" type="checkbox"><span>控制台调试</span></label>
            <label class="checkbox_label" title="开启后，只给 user/assistant 消息套模板；history 区间内的其它结构片段会作为同一条输出消息的普通文本拼入。"><input id="hs-template-dialogue-only" type="checkbox"><span>只标记 user/assistant</span></label>
          </div>

          <div class="hs-grid">
            <label class="hs-field">开始 marker
              <input id="hs-start" class="text_pole" type="text">
            </label>
            <label class="hs-field">结束 marker
              <input id="hs-end" class="text_pole" type="text">
            </label>
          </div>

          <div class="hs-grid">
            <label class="hs-field">输出 role
              <select id="hs-role" class="text_pole">
                <option value="assistant">assistant</option>
                <option value="user">user</option>
                <option value="system">system</option>
              </select>
            </label>
            <label class="hs-field">块间分隔符（可写 \n）
              <input id="hs-joiner" class="text_pole" type="text">
            </label>
          </div>

          <label class="hs-field">单条消息模板
            <textarea id="hs-template" class="text_pole textarea_compact" spellcheck="false"></textarea>
          </label>
          <div class="hs-note">变量：<code>{{role}}</code>、<code>{{rawRole}}</code>、<code>{{content}}</code></div>

          <div class="inline-drawer">
            <div class="inline-drawer-toggle inline-drawer-header">
              <b>角色标签</b>
              <div class="inline-drawer-icon fa-solid fa-circle-chevron-down down"></div>
            </div>
            <div class="inline-drawer-content">
              <div class="hs-grid">
                <label class="hs-field">user <input id="hs-label-user" class="text_pole" type="text"></label>
                <label class="hs-field">assistant <input id="hs-label-assistant" class="text_pole" type="text"></label>
                <label class="hs-field">system <input id="hs-label-system" class="text_pole" type="text"></label>
                <label class="hs-field">tool <input id="hs-label-tool" class="text_pole" type="text"></label>
              </div>
            </div>
          </div>

          <div class="hs-actions">
            <div id="hs-save" class="menu_button menu_button_icon"><i class="fa-solid fa-save"></i><small>保存</small></div>
            <div id="hs-reset" class="menu_button menu_button_icon"><i class="fa-solid fa-rotate-left"></i><small>重置</small></div>
            <div id="hs-fill-sample" class="menu_button menu_button_icon"><i class="fa-solid fa-vial"></i><small>样例</small></div>
            <div id="hs-preview" class="menu_button menu_button_icon"><i class="fa-solid fa-play"></i><small>预览</small></div>
            <div id="hs-load-last" class="menu_button menu_button_icon"><i class="fa-solid fa-clock"></i><small>上次发送</small></div>
          </div>

          <label class="hs-field">调试输入：prompt JSON 数组
            <textarea id="hs-input" class="text_pole textarea_compact" spellcheck="false"></textarea>
          </label>
          <label class="hs-field">输出
            <textarea id="hs-output" class="text_pole textarea_compact hs-output" spellcheck="false" readonly></textarea>
          </label>
          <div id="history-squash-status" class="hs-note"></div>
        </div>
      </div>
    `;
    mount.appendChild(root);

    bindPanelEvents(root);
    state.uiMountedAt = new Date().toISOString();
    console.info('[HistorySquash] UI 已挂载到', mount.id);
    return true;
  }

  /**
   * 绑定 UI 事件。
   *
   * 这里使用事件委托，只处理按钮区域。
   * 不拦截 inline-drawer-toggle，让 SillyTavern 原生 drawer 逻辑接管。
   */
  function bindPanelEvents(root) {
    const $ = selector => root.querySelector(selector);
    const fields = {
      enabled: $('#hs-enabled'),
      debug: $('#hs-debug'),
      templateDialogueOnly: $('#hs-template-dialogue-only'),
      start: $('#hs-start'),
      end: $('#hs-end'),
      role: $('#hs-role'),
      joiner: $('#hs-joiner'),
      template: $('#hs-template'),
      labelUser: $('#hs-label-user'),
      labelAssistant: $('#hs-label-assistant'),
      labelSystem: $('#hs-label-system'),
      labelTool: $('#hs-label-tool'),
      input: $('#hs-input'),
      output: $('#hs-output'),
      status: $('#history-squash-status'),
    };

    function showSettings() {
      const s = state.settings;
      fields.enabled.checked = !!s.enabled;
      fields.debug.checked = !!s.debug;
      fields.templateDialogueOnly.checked = s.templateDialogueOnly !== false;
      fields.start.value = s.startMarker;
      fields.end.value = s.endMarker;
      fields.role.value = s.outputRole;
      fields.joiner.value = s.joiner.replaceAll('\n', '\\n');
      fields.template.value = s.blockTemplate;
      fields.labelUser.value = s.labels.user || 'User';
      fields.labelAssistant.value = s.labels.assistant || 'Assistant';
      fields.labelSystem.value = s.labels.system || 'System';
      fields.labelTool.value = s.labels.tool || 'Tool';
    }

    function readSettings() {
      state.settings = mergeSettings(DEFAULT_SETTINGS, {
        enabled: fields.enabled.checked,
        debug: fields.debug.checked,
        templateDialogueOnly: fields.templateDialogueOnly.checked,
        startMarker: fields.start.value || DEFAULT_SETTINGS.startMarker,
        endMarker: fields.end.value || DEFAULT_SETTINGS.endMarker,
        outputRole: fields.role.value || DEFAULT_SETTINGS.outputRole,
        joiner: fields.joiner.value.replaceAll('\\n', '\n'),
        blockTemplate: fields.template.value || DEFAULT_SETTINGS.blockTemplate,
        labels: {
          user: fields.labelUser.value || 'User',
          assistant: fields.labelAssistant.value || 'Assistant',
          system: fields.labelSystem.value || 'System',
          tool: fields.labelTool.value || 'Tool',
        },
      });
    }

    function fillSample() {
      readSettings();
      fields.input.value = stringifyPrompt([
        { role: 'system', content: `before\n${state.settings.startMarker}` },
        { role: 'user', content: '你好' },
        { role: 'assistant', content: '你好，有什么可以帮你？' },
        { role: 'user', content: '写一段测试' },
        { role: 'system', content: `${state.settings.endMarker}\nafter` },
      ]);
      fields.output.value = '';
      fields.status.textContent = '已填入样例。点击“预览”查看转换结果。';
    }

    root.addEventListener('click', event => {
      const action = event.target.closest('#hs-save, #hs-reset, #hs-fill-sample, #hs-preview, #hs-load-last');
      if (!action || !root.contains(action)) return;

      // 只阻止按钮自身默认行为，不阻止 drawer 标题事件。
      event.preventDefault();

      if (action.id === 'hs-save') {
        readSettings();
        saveSettings();
        fields.status.textContent = '已保存到 localStorage。';
        return;
      }

      if (action.id === 'hs-reset') {
        state.settings = structuredCloneCompat(DEFAULT_SETTINGS);
        saveSettings();
        showSettings();
        fields.status.textContent = '已重置。';
        return;
      }

      if (action.id === 'hs-fill-sample') {
        fillSample();
        return;
      }

      if (action.id === 'hs-preview') {
        readSettings();
        const result = runPreview(fields.input.value);
        fields.output.value = result.text;
        fields.status.textContent = result.ok ? `转换完成。changed=${result.changed}` : result.text;
        return;
      }

      if (action.id === 'hs-load-last') {
        fields.input.value = stringifyPrompt(state.lastBefore || []);
        fields.output.value = stringifyPrompt(state.lastAfter || []);
        fields.status.textContent = state.lastBefore ? `已载入上次发送。changed=${state.lastChanged}` : '还没有捕获到发送请求。';
      }
    });

    showSettings();
  }

  /**
   * 尝试挂载 UI。
   *
   * 这个函数可以被 ST 事件、DOM observer、手动 API 调用。
   */
  function ensurePanel() {
    return createPanel();
  }

  /**
   * 安装 DOM 监听。
   *
   * 这里使用 MutationObserver 的原因：
   * ST 或第三方加载器可能在脚本执行之后才渲染扩展区域，
   * 也可能在切换页面/重新渲染时移除已挂载的 UI。
   *
   * MutationObserver 是事件式监听，不是轮询。
   */
  function installDomObservers() {
    if (state.uiObservers.length > 0) return;

    for (const win of getCandidateWindows()) {
      try {
        const doc = win.document;
        if (!doc?.body) continue;

        const observer = new win.MutationObserver(() => {
          const hasMount = !!doc.querySelector('#extensions_settings, #extensions_settings2');
          const hasPanel = !!doc.getElementById('history-squash-settings');

          if (hasMount && !hasPanel) createPanel();
          if (!state.installed && getSillyTavernContext()) install();
        });

        observer.observe(doc.body, { childList: true, subtree: true });
        state.uiObservers.push(observer);
      } catch {
        // 不可访问窗口，忽略。
      }
    }
  }

  // ===========================================================================
  // 6. SillyTavern 事件安装与调试 API
  // ===========================================================================

  function handleGenerateAfterData(data) {
    if (!Array.isArray(data?.prompt)) return;

    state.lastBefore = structuredCloneCompat(data.prompt);

    if (squashHistoryBetweenMarkers(data.prompt)) {
      state.lastChanged = true;
      state.lastAfter = structuredCloneCompat(data.prompt);
      if (state.settings.debug) {
        console.debug('[HistorySquash] 已压缩 marker 区间内的历史消息。', data.prompt);
      }
    } else {
      state.lastChanged = false;
      state.lastAfter = structuredCloneCompat(data.prompt);
    }
  }

  function diagnose() {
    const uiDocument = getUIDocument();
    const root = uiDocument.getElementById('history-squash-settings');
    const mount1 = uiDocument.querySelector('#extensions_settings');
    const mount2 = uiDocument.querySelector('#extensions_settings2');
    const ctx = getSillyTavernContext();

    const info = {
      installed: state.installed,
      enabled: state.settings.enabled,
      debug: state.settings.debug,
      readyState: uiDocument.readyState,
      uiExists: !!root,
      uiInBody: !!root && uiDocument.body?.contains(root),
      uiMountedAt: state.uiMountedAt,
      uiMountAttempts: state.uiMountAttempts,
      uiObservers: state.uiObservers.length,
      hasExtensionsSettings: !!mount1,
      hasExtensionsSettings2: !!mount2,
      extensionsSettingsChildren: mount1?.children?.length ?? null,
      extensionsSettings2Children: mount2?.children?.length ?? null,
      hasExtensionsBlock: !!uiDocument.querySelector('#rm_extensions_block'),
      hasContext: !!ctx,
      hasGenerateEvent: !!ctx?.eventTypes?.GENERATE_AFTER_DATA,
      lastChanged: state.lastChanged,
      hasLastBefore: !!state.lastBefore,
      hasLastAfter: !!state.lastAfter,
    };

    console.table(info);
    return info;
  }

  function getApi() {
    return {
      squashHistoryBetweenMarkers,
      runPreview,
      getSettings: () => structuredCloneCompat(state.settings),
      setSettings: nextSettings => {
        state.settings = mergeSettings(state.settings, nextSettings || {});
        saveSettings();
      },
      getLast: () => ({
        before: structuredCloneCompat(state.lastBefore),
        after: structuredCloneCompat(state.lastAfter),
        changed: state.lastChanged,
      }),
      mount: ensurePanel,
      diagnose,
    };
  }

  /**
   * 安装脚本。
   *
   * 安装顺序：
   * 1. 暴露 API，保证脚本即使尚未拿到 ST context，也能诊断。
   * 2. 安装 DOM observer，等待扩展设置区域出现。
   * 3. 若 ST context 已就绪，监听 GENERATE_AFTER_DATA。
   * 4. 尝试挂载 UI。
   */
  function install() {
    exposeApi(getApi());
    installDomObservers();

    if (state.installed) {
      ensurePanel();
      return;
    }

    const ctx = getSillyTavernContext();
    if (!ctx?.eventSource || !ctx?.eventTypes?.GENERATE_AFTER_DATA) {
      console.warn('[HistorySquash] SillyTavern context 尚未就绪；等待 DOM/ST 事件。');
      ensurePanel();
      return;
    }

    ctx.eventSource.on(ctx.eventTypes.GENERATE_AFTER_DATA, handleGenerateAfterData);

    // 如果当前 EventSource 支持 makeLast，则让本脚本尽量靠后执行。
    // 这样可以在 ST 和其他扩展完成 prompt 构建后再做最终重排。
    ctx.eventSource.makeLast?.(ctx.eventTypes.GENERATE_AFTER_DATA, handleGenerateAfterData);

    if (ctx.eventTypes.APP_READY) ctx.eventSource.on?.(ctx.eventTypes.APP_READY, ensurePanel);
    if (ctx.eventTypes.SETTINGS_LOADED) ctx.eventSource.on?.(ctx.eventTypes.SETTINGS_LOADED, ensurePanel);

    ensurePanel();
    state.installed = true;
    console.info('[HistorySquash] 已安装。请在扩展面板配置 marker 与输出格式。');
  }

  // ===========================================================================
  // 7. 启动：纯事件式，无轮询
  // ===========================================================================

  function bootstrap() {
    exposeApi(getApi());
    install();

    for (const win of getCandidateWindows()) {
      try {
        win.addEventListener('load', install, { once: true });
        win.addEventListener('pageshow', install);
        win.document?.addEventListener?.('readystatechange', install);
        if (win.document?.readyState === 'loading') {
          win.document.addEventListener('DOMContentLoaded', install, { once: true });
        }
      } catch {
        // 不可访问窗口，忽略。
      }
    }
  }

  bootstrap();
})();

